#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e5 + 5;
vector<int> v[MAXN];
int n, k, sum[MAXN], ans;
void dfs(int a, int b)
{
	sum[a] = 1;
	for (auto k : v[a])
		if (k != b)
		{
			dfs(k, a);
			sum[a] += sum[k];
		}
	if (sum[a] == k)sum[a] = 0, ++ans;
	return;
}
int main(void)
{
	for (int t = read(); t; --t)
	{
		cin >> n >> k;
		for (int i = 1; i <= n; ++i)v[i].clear();
		for (int i = 1, x, y; i < n; ++i)
		{
			cin >> x >> y;
			v[x].push_back(y);
			v[y].push_back(x);
		}
		if (n % k)
		{
			puts("NO");
			continue;
		}
		ans = 0;
		dfs(1, 0);
		if (ans == n / k)puts("YES");
		else puts("NO");
	}
	return false;
}
